#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

struct Node{
    int a,b,c,id;
}p[N],t[N];

int n,k,cnt[N],ans[N],c[N*2];

bool cmp(Node x,Node y){
    return x.a<y.a;
}

bool cmp2(Node x,Node y){
    return x.id>y.id;
}

void add(int x,int val){
    for(;x<=k;x+=(x&(-x)))
        c[x]+=val;
}

int ask(int x){
    int res=0;
    for(;x;x-=(x&(-x)))
        res+=c[x];
    return res;
}

void Del(int x){
	for(;x<=k;x+=(x&(-x)))
		c[x]=0;
}

void CDQ(int l,int r){
    if(l==r)
        return;
    int mid=l+r>>1,tot=l-1;
    CDQ(l,mid);
    CDQ(mid+1,r);
    int i,j;
    for(i=mid+1,j=l;i<=r;i++){
        while(j<=mid && p[j].b<=p[i].b){
            add(p[j].c,1);
            t[++tot]=p[j];
            j++;
        }
        cnt[p[i].id]+=ask(p[i].c);
        t[++tot]=p[i];
    }
    while(j<=mid){
    	t[++tot]=p[j];
    	j++;
	}
    for(i=l;i<=mid;i++)
        Del(p[i].c);
    for(i=l;i<=r;i++)
        p[i]=t[i];
}

int main(){
    scanf("%d%d",&n,&k);
    for(int i=1;i<=n;i++)
        scanf("%d%d%d",&p[i].a,&p[i].b,&p[i].c);
    sort(p+1,p+n+1,cmp);
    for(int i=1;i<=n;i++)
        p[i].id=i;
    CDQ(1,n);
    sort(p+1,p+n+1,cmp2);
    for(int i=1,j=1;i<=n;i++)
        if(p[i+1].a!=p[i].a){
            CDQ(j,i);
            j=i+1;
        }
    for(int i=1;i<=n;i++)
        ans[cnt[i]]++;
    for(int i=0;i<n;i++)
        printf("%d\n",ans[i]);
    return 0;
}
